var assembly = Assembly.GetExecutingAssembly();
using (Stream stream = assembly.GetManifestResourceStream(profile.GetManifestName()))
{
    var span = BinaryData.FromStream(stream).ToMemory();
    using var doc = JsonDocument.Parse(span);
    var root = doc.RootElement;
    var armProfile = root.GetProperty("resource-manager");
    foreach (var nsProperty in armProfile.EnumerateObject())
    {
        var namespaceName = nsProperty.Name;
        var element = nsProperty.Value;

